import os
import sys
import boto3

def main():
    region = os.environ.get("AWS_REGION") or os.environ.get("AWS_DEFAULT_REGION") or "us-east-1"
    topic_arn = os.environ.get("SNS_TOPIC_ARN")

    if not topic_arn:
        print("Error: SNS_TOPIC_ARN environment variable is required.", file=sys.stderr)
        sys.exit(1)

    sns = boto3.client("sns", region_name=region)

    print("Enter subscription endpoints (one per line).")
    print("Press Ctrl-D (Unix/macOS) or Ctrl-Z then Enter (Windows) to finish.\n")

    endpoints = []
    try:
        for line in sys.stdin:
            endpoint = line.strip()
            if endpoint:
                endpoints.append(endpoint)
    except KeyboardInterrupt:
        pass

    if not endpoints:
        print("No endpoints provided.", file=sys.stderr)
        sys.exit(1)

    results = []
    for endpoint in endpoints:
        try:
            resp = sns.subscribe(
                TopicArn=topic_arn,
                Protocol="https",
                Endpoint=endpoint
            )
            results.append((endpoint, resp.get("SubscriptionArn", "")))
        except Exception as e:
            results.append((endpoint, f"ERROR: {e}"))

    for endpoint, arn in results:
        print(f"{endpoint}\t{arn}")

if __name__ == "__main__":
    main()